import React, { useEffect, useRef } from 'react';
import { toCanvas } from 'qrcode';
import './QRCode.css';

const QRCodePage = () => {
  const canvasRef = useRef(null);
  const menuUrl = `${window.location.origin}/menu`;

  useEffect(() => {
    if (canvasRef.current) {
      toCanvas(canvasRef.current, menuUrl, {
        width: 256,
        margin: 1,
        color: {
          dark: '#000000',
          light: '#FFFFFF'
        }
      });
    }
  }, []);

  const handleDownload = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const link = document.createElement('a');
      link.download = 'restaurant-menu-qr.png';
      link.href = canvas.toDataURL();
      link.click();
    }
  };

  const testMenu = () => {
    window.open(menuUrl, '_blank');
  };

  return (
    <div className="qrcode-page">
      <div className="page-header">
        <h1>📱 QR Menu</h1>
        <p>Single QR for full restaurant menu</p>
      </div>

      <div className="qr-container">
        <canvas ref={canvasRef} />
        <div className="qr-info">
          <p><strong>URL:</strong> {menuUrl}</p>
          <p>Print & place on tables - customers scan → full menu</p>
        </div>
      </div>

      <div className="qr-actions">
        <button onClick={handleDownload}>💾 Download</button>
        <button onClick={testMenu}>🧪 Test</button>
      </div>
    </div>
  );
};

export default QRCodePage;
